import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators, AbstractControl, ValidationErrors } from '@angular/forms';
import { Router } from '@angular/router';
import { AuthService } from '../../services/auth.service';

function passwordMatch(group: AbstractControl): ValidationErrors | null {
  const pw = group.get('password')?.value;
  const cpw = group.get('confirmPassword')?.value;
  return pw && cpw && pw !== cpw ? { mismatch: true } : null;
}

@Component({
  selector: 'app-register',
  templateUrl: './register.component.html',
  styleUrls: ['./register.component.css']
})
export class RegisterComponent implements OnInit {
  form!: FormGroup;
  errorMessage = '';
  successMessage = '';
  isLoading = false;
  showPassword = false;
  showConfirm = false;

  constructor(
    private fb: FormBuilder,
    private authService: AuthService,
    private router: Router
  ) {}

  ngOnInit(): void {
    if (this.authService.isLoggedIn()) {
      this.router.navigate(['/profile']);
      return;
    }
    this.form = this.fb.group({
      username: ['', [Validators.required, Validators.minLength(3), Validators.pattern(/^[a-zA-Z0-9_]+$/)]],
      email: ['', [Validators.required, Validators.email]],
      password: ['', [Validators.required, Validators.minLength(6)]],
      confirmPassword: ['', Validators.required]
    }, { validators: passwordMatch });
  }

  onSubmit(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }

    this.isLoading = true;
    this.errorMessage = '';

    const { username, email, password } = this.form.value;
    this.authService.register({ username, email, password }).subscribe({
      next: () => {
        this.isLoading = false;
        this.router.navigate(['/personal-details']);
      },
      error: (err) => {
        this.isLoading = false;
        this.errorMessage = err.error?.message || 'Registration failed. Please try again.';
      }
    });
  }

  err(field: string): string {
    const c = this.form.get(field);
    if (!c?.touched || !c.errors) return '';
    if (c.errors['required']) return 'This field is required.';
    if (c.errors['minlength']) return `Minimum ${c.errors['minlength'].requiredLength} characters required.`;
    if (c.errors['email']) return 'Please enter a valid email address.';
    if (c.errors['pattern']) return 'Only letters, numbers, and underscores allowed.';
    return '';
  }
}
<div class="auth-page">
  <div class="auth-card">

    <div class="auth-header">
      <div class="auth-logo">&#9670;</div>
      <h1>Create Account</h1>
      <p>Fill in your details to get started</p>
    </div>

    <div class="alert alert-error" *ngIf="errorMessage">
      <span>&#9888;</span> {{ errorMessage }}
    </div>

    <form [formGroup]="form" (ngSubmit)="onSubmit()" novalidate>

      <div class="form-group">
        <label for="username">Username</label>
        <input
          id="username"
          type="text"
          formControlName="username"
          placeholder="Choose a username (letters, numbers, _)"
          [class.error]="form.get('username')?.touched && form.get('username')?.invalid"
          autocomplete="username"
        />
        <span class="error-text" *ngIf="err('username')">{{ err('username') }}</span>
      </div>

      <div class="form-group">
        <label for="email">Email Address</label>
        <input
          id="email"
          type="email"
          formControlName="email"
          placeholder="Enter your email address"
          [class.error]="form.get('email')?.touched && form.get('email')?.invalid"
          autocomplete="email"
        />
        <span class="error-text" *ngIf="err('email')">{{ err('email') }}</span>
      </div>

      <div class="form-group">
        <label for="password">Password</label>
        <div class="input-icon-group">
          <input
            id="password"
            [type]="showPassword ? 'text' : 'password'"
            formControlName="password"
            placeholder="Minimum 6 characters"
            [class.error]="form.get('password')?.touched && form.get('password')?.invalid"
            autocomplete="new-password"
          />
          <button type="button" class="toggle-pw" (click)="showPassword = !showPassword" tabindex="-1">
            {{ showPassword ? 'Hide' : 'Show' }}
          </button>
        </div>
        <span class="error-text" *ngIf="err('password')">{{ err('password') }}</span>
      </div>

      <div class="form-group">
        <label for="confirmPassword">Confirm Password</label>
        <div class="input-icon-group">
          <input
            id="confirmPassword"
            [type]="showConfirm ? 'text' : 'password'"
            formControlName="confirmPassword"
            placeholder="Re-enter your password"
            [class.error]="form.get('confirmPassword')?.touched && (form.get('confirmPassword')?.invalid || form.errors?.['mismatch'])"
            autocomplete="new-password"
          />
          <button type="button" class="toggle-pw" (click)="showConfirm = !showConfirm" tabindex="-1">
            {{ showConfirm ? 'Hide' : 'Show' }}
          </button>
        </div>
        <span class="error-text" *ngIf="form.get('confirmPassword')?.touched && form.errors?.['mismatch']">
          Passwords do not match.
        </span>
        <span class="error-text" *ngIf="err('confirmPassword') && !form.errors?.['mismatch']">{{ err('confirmPassword') }}</span>
      </div>

      <button type="submit" class="btn-primary" [disabled]="isLoading">
        <span class="spinner" *ngIf="isLoading"></span>
        <span *ngIf="!isLoading">Create Account</span>
      </button>

    </form>

    <div class="auth-footer">
      Already have an account? <a routerLink="/login">Sign in here</a>
    </div>

  </div>
</div>
